sparql_query:
PREFIX goo:    <https://ucf-henat.github.io/GeoOutageOnto/#>
PREFIX gokg:   <http://example.org/resource#>
PREFIX xsd:    <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf:    <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs:   <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?neighborCounty ?sviRecord ?sviScore ?maxOutages
WHERE {
  gokg:LeeCountyFL goo:neighboringCounties ?neighborCounty .
  ?sviRecord a goo:SVIRecord ;
             goo:representsCounty ?neighborCounty ;
             goo:sviYear 2022 ;
             goo:sviOverallScore ?sviScore .
  {
    SELECT ?neighborCounty (MAX(?numOutages) AS ?maxOutages)
    WHERE {
      ?record a goo:CustomerOutageRecord ;
              goo:representsCounty ?neighborCounty ;
              goo:recordDateTime ?recordDate ;
              goo:numberOfOutages ?numOutages .
      FILTER (?recordDate >= "2022-09-23T00:00:00Z"^^xsd:dateTime && ?recordDate < "2022-10-08T00:00:00Z"^^xsd:dateTime)
    }
    GROUP BY ?neighborCounty
  }
  FILTER (?sviScore >= 0.5 && ?maxOutages > 100000)
}
ORDER BY DESC(?sviScore) DESC(?maxOutages)
